import React, { useState, useEffect } from 'react';
import API from '../api/axios';
import Navigation from '../components/Navigation';

const BlockMaster = () => {
    const [blocks, setBlocks] = useState([]);
    const [departments, setDepartments] = useState([]);
    const [programmes, setProgrammes] = useState([]);
    const [formData, setFormData] = useState({ department: '', programme: '', blockName: '' });
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');
    const [isEditing, setIsEditing] = useState(false);
    const [editId, setEditId] = useState(null);

    useEffect(() => { fetchBlocks(); fetchProgrammes(); }, []);

    const fetchBlocks = async () => {
        try { const { data } = await API.get('/master/block'); setBlocks(data); }
        catch (err) { setMessage({ type: 'error', text: 'Error fetching blocks' }); }
    };

    const fetchProgrammes = async () => {
        try {
            const { data } = await API.get('/master/programme');
            setProgrammes(data);
        } catch (err) { setMessage({ type: 'error', text: 'Error fetching programmes' }); }
    };

    const handleProgrammeChange = (e) => {
        const progId = e.target.value;
        const selectedProg = programmes.find(p => p._id === progId);
        setFormData({ 
            ...formData, 
            programme: progId, 
            department: selectedProg?.department?._id || ''
        });
    };

    const handleEdit = (block) => {
        setIsEditing(true);
        setEditId(block._id);
        setFormData({ 
            department: block.department?._id || '', 
            programme: block.programme?._id || '', 
            blockName: block.blockName 
        });
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    const handleDelete = async (id) => {
        if (!window.confirm('Are you sure you want to delete this block?')) return;
        try {
            await API.delete(`/master/block/${id}`);
            fetchBlocks();
            setMessage({ type: 'success', text: '✓ Block deleted successfully!' });
            setTimeout(() => setMessage(''), 3000);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error deleting block' });
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            if (isEditing) {
                await API.put(`/master/block/${editId}`, formData);
                setMessage({ type: 'success', text: '✓ Block updated successfully!' });
            } else {
                await API.post('/master/block', formData);
                setMessage({ type: 'success', text: '✓ Block added successfully!' });
            }
            setFormData({ department: '', programme: '', blockName: '' });
            setIsEditing(false);
            setEditId(null);
            fetchBlocks();
            setTimeout(() => setMessage(''), 3000);
        } catch (err) {
            setMessage({ type: 'error', text: isEditing ? 'Error updating block' : 'Error adding block' });
        } finally { setLoading(false); }
    };

    const resetForm = () => {
        setFormData({ department: '', programme: '', blockName: '' });
        setIsEditing(false);
        setEditId(null);
    };

    return (
        <div className="page-wrapper">
            <Navigation />
            <div className="content-area">
                <div className="header-section">
                    <h1 className="main-title">🏠 Block Master</h1>
                    <p className="subtitle">Manage building blocks and their associations</p>
                </div>

                {message && (
                    <div className={`alert ${message.type === 'success' ? 'alert-success' : 'alert-error'}`}>
                        {message.text}
                    </div>
                )}

                <div className="master-grid">
                    <div className="glass-card">
                        <form onSubmit={handleSubmit} className="form-body">
                            <h3 className="form-title">{isEditing ? '✏️ Edit Block' : '➕ Add New Block'}</h3>
                            <div className="form-group">
                                <label className="form-label">Programme / Course</label>
                                <select required value={formData.programme}
                                    onChange={handleProgrammeChange}
                                    className="form-select">
                                    <option value="">Select Programme</option>
                                    {programmes.map(prog => (
                                        <option key={prog._id} value={prog._id}>
                                            {prog.programmeName} ({prog.programmeShortName}) - {prog.department?.deptName}
                                        </option>
                                    ))}
                                </select>
                            </div>
                            <div className="form-group">
                                <label className="form-label">Block Name</label>
                                <input type="text" required value={formData.blockName}
                                    onChange={e => setFormData({ ...formData, blockName: e.target.value })}
                                    className="form-input" placeholder="e.g., Block A, Main Building..." />
                            </div>
                            <div className="form-actions">
                                <button type="submit"
                                    disabled={loading || !formData.programme || !formData.blockName}
                                    className="btn btn-primary" style={{ flex: 1 }}>
                                    {loading ? 'Processing...' : (isEditing ? 'Update Block' : '+ Add Block')}
                                </button>
                                {isEditing && (
                                    <button type="button" onClick={resetForm} className="btn btn-secondary">
                                        Cancel
                                    </button>
                                )}
                            </div>
                        </form>
                    </div>

                    <div className="table-card">
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '18px' }}>
                            <h3 className="table-title" style={{ marginBottom: 0 }}>📋 All Blocks</h3>
                            <span className="badge badge-primary">{blocks.length} Blocks</span>
                        </div>
                        <div className="table-scroll">
                            <table className="data-table">
                                <thead>
                                    <tr>
                                        <th>Department</th>
                                        <th>Programme</th>
                                        <th>Block Name</th>
                                        <th style={{ textAlign: 'center' }}>Actions</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {blocks.length > 0 ? (
                                        blocks.map(block => (
                                            <tr key={block._id}>
                                                <td>{block.department?.deptName || block.department?.department || 'N/A'}</td>
                                                <td>{block.programme?.programmeName || block.programme?.programme || 'N/A'}</td>
                                                <td><span className="badge badge-accent">{block.blockName}</span></td>
                                                <td className="table-actions">
                                                    <button onClick={() => handleEdit(block)} className="btn-icon-only" title="Edit">✏️</button>
                                                    <button onClick={() => handleDelete(block._id)} className="btn-icon-only text-error" title="Delete">🗑️</button>
                                                </td>
                                            </tr>
                                        ))
                                    ) : (
                                        <tr><td colSpan="4" className="table-empty">No blocks found. Add your first block above.</td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default BlockMaster;
